FILES = {
    'src/app/features/mapa/embed/mapa-embed.routes.ts': "import { Routes } from '@angular/router';\n\nexport const MAPA_EMBED_ROUTES: Routes = [\n  {\n    path: '',\n    pathMatch: 'full',\n    redirectTo: 'admin',\n  },\n  {\n    path: 'admin',\n    data: { mode: 'admin' },\n    loadComponent: () =>\n      import('./pages/mapa-embed-admin-shell/mapa-embed-admin-shell.component').then(\n        (m) => m.MapaEmbedAdminShellComponent\n      ),\n  },\n  {\n    path: 'vendedor',\n    data: { mode: 'vendedor' },\n    loadComponent: () =>\n      import('./pages/mapa-embed-viewer/mapa-embed-viewer.component').then(\n        (m) => m.MapaEmbedViewerComponent\n      ),\n  },\n  {\n    path: 'tecnico',\n    data: { mode: 'tecnico' },\n    loadComponent: () =>\n      import('./pages/mapa-embed-viewer/mapa-embed-viewer.component').then(\n        (m) => m.MapaEmbedViewerComponent\n      ),\n  },\n  {\n    path: '**',\n    redirectTo: 'admin',\n  },\n];\n",
    'src/app/features/mapa/embed/data-access/mapa-embed.models.ts': "import type { DynamicMenuItem } from 'src/app/features/seg/store/session.store';\n\nexport type MapaEmbedMode = 'admin' | 'vendedor' | 'tecnico';\n\nexport interface MapaEmbedContext {\n  mode: MapaEmbedMode;\n  company: string;\n  tenant: string;\n  usu: number;\n  usuario: string;\n\n  lat?: number | null;\n  lng?: number | null;\n  direccion?: string | null;\n  radioM?: number | null;\n\n  trabajoId?: number | null;\n  clienteId?: number | null;\n  ordenId?: number | null;\n\n  metadata?: Record<string, unknown> | null;\n}\n\nexport interface MapaEmbedConfig {\n  mode: MapaEmbedMode;\n  tiposElemento: number[];\n  distanciaM: number;\n  acciones: string[];\n  privilegios: Record<string, boolean>;\n}\n\nexport interface MapaEmbedExchangeRequest {\n  code: string;\n}\n\nexport interface MapaEmbedExchangeResponse {\n  token: string;\n  usuario: string;\n  usu: number;\n  catalogo?: string | null;\n  tipo?: number | null;\n  organizacion?: unknown[] | null;\n\n  contextPath?: string | null;\n  environment?: string | null;\n\n  privilegiosEmpresa?: string[] | null;\n  menusEmpresa?: DynamicMenuItem[] | null;\n\n  embed: MapaEmbedContext;\n  embedConfig: MapaEmbedConfig;\n}\n\nexport interface MapaElementoCercano {\n  idGeoElemento: number;\n  idRedNodoFk: number;\n  idGeoTipoElementoFk: number;\n\n  tipoCodigo?: string | null;\n  tipoNombre?: string | null;\n\n  codigo?: string | null;\n  nombre: string;\n  descripcion?: string | null;\n  etiqueta?: string | null;\n\n  estado?: string | null;\n  visible?: boolean | null;\n\n  geomTipo?: 'point' | 'linestring' | 'polygon' | string | null;\n  wkt?: string | null;\n  latLon?: string | null;\n  bbox?: string | null;\n\n  longitudM?: number | null;\n  areaM2?: number | null;\n  ordenDibujo?: number | null;\n\n  distanciaM?: number | null;\n}\n\nexport interface MapaElementosCercanosResponse {\n  mode: MapaEmbedMode;\n  lat: number;\n  lng: number;\n  radioM: number;\n  total: number;\n  items: MapaElementoCercano[];\n}\n\nexport interface MapaEmbedInitMessage {\n  type: 'KLAX_MAP_INIT';\n  mode?: MapaEmbedMode;\n  lat?: number;\n  lng?: number;\n  direccion?: string;\n  radioM?: number;\n  trabajoId?: number;\n  clienteId?: number;\n  ordenId?: number;\n  metadata?: Record<string, unknown>;\n}\n",
    'src/app/features/mapa/embed/data-access/mapa-embed.api.ts': "import { HttpClient, HttpContext, HttpHeaders, HttpParams } from '@angular/common/http';\nimport { inject, Injectable } from '@angular/core';\nimport { ENVIRONMENT } from 'src/app/core/config/environment.token';\nimport type { AppEnvironment } from 'src/app/core/config/environment.token';\nimport { SKIP_AUTH, SKIP_TENANT } from 'src/app/core/http/http-context.tokens';\nimport type { ApiEnvelope } from 'src/app/core/api/api-envelope';\nimport type {\n  MapaEmbedContext,\n  MapaEmbedConfig,\n  MapaEmbedExchangeRequest,\n  MapaEmbedExchangeResponse,\n  MapaEmbedMode,\n  MapaElementosCercanosResponse,\n} from './mapa-embed.models';\n\nconst PUBLIC = new HttpContext().set(SKIP_AUTH, true).set(SKIP_TENANT, true);\n\n@Injectable({ providedIn: 'root' })\nexport class MapaEmbedApi {\n  private readonly http = inject(HttpClient);\n  private readonly env = inject<AppEnvironment>(ENVIRONMENT);\n\n  private readonly authBaseUrl = `${this.env.apiBaseUrl}/api/aut/embed`;\n  private readonly erpBaseUrl = `${this.env.apiBaseUrl}/api/erp`;\n\n  exchange(payload: MapaEmbedExchangeRequest) {\n    return this.http.post<MapaEmbedExchangeResponse>(`${this.authBaseUrl}/exchange`, payload, {\n      context: PUBLIC,\n    });\n  }\n\n  getConfig(modo: MapaEmbedMode, ctx?: MapaEmbedContext | null) {\n    const params = new HttpParams().set('modo', modo);\n    return this.http.get<ApiEnvelope<MapaEmbedConfig>>(`${this.erpBaseUrl}/mapa/embed/config`, {\n      params,\n      headers: this.headersFromContext(ctx),\n    });\n  }\n\n  getElementosCercanos(params: {\n    modo: MapaEmbedMode;\n    lat: number;\n    lng: number;\n    radioM?: number | null;\n    limit?: number | null;\n    ctx?: MapaEmbedContext | null;\n  }) {\n    let httpParams = new HttpParams()\n      .set('modo', params.modo)\n      .set('lat', String(params.lat))\n      .set('lng', String(params.lng));\n\n    if (params.radioM != null) httpParams = httpParams.set('radioM', String(params.radioM));\n    if (params.limit != null) httpParams = httpParams.set('limit', String(params.limit));\n\n    return this.http.get<ApiEnvelope<MapaElementosCercanosResponse>>(\n      `${this.erpBaseUrl}/mapa/elemento/cercanos`,\n      {\n        params: httpParams,\n        headers: this.headersFromContext(params.ctx),\n      }\n    );\n  }\n\n  private headersFromContext(ctx?: MapaEmbedContext | null) {\n    if (!ctx?.company || !ctx?.tenant) return undefined;\n\n    return new HttpHeaders({\n      'X-Company': ctx.company,\n      'X-Tenant': ctx.tenant,\n    });\n  }\n}\n",
    'src/app/features/mapa/embed/store/mapa-embed-context.store.ts': "import { computed, Injectable, signal } from '@angular/core';\nimport type {\n  MapaEmbedConfig,\n  MapaEmbedContext,\n  MapaEmbedExchangeResponse,\n  MapaEmbedMode,\n} from '../data-access/mapa-embed.models';\n\n@Injectable({ providedIn: 'root' })\nexport class MapaEmbedContextStore {\n  private readonly _context = signal<MapaEmbedContext | null>(null);\n  private readonly _config = signal<MapaEmbedConfig | null>(null);\n  private readonly _postMessageOrigin = signal<string>('*');\n\n  readonly context = computed(() => this._context());\n  readonly config = computed(() => this._config());\n  readonly postMessageOrigin = computed(() => this._postMessageOrigin());\n\n  readonly mode = computed<MapaEmbedMode | null>(() => this._context()?.mode ?? null);\n  readonly isAdmin = computed(() => this.mode() === 'admin');\n  readonly isVendedor = computed(() => this.mode() === 'vendedor');\n  readonly isTecnico = computed(() => this.mode() === 'tecnico');\n\n  setPostMessageOrigin(origin: string | null | undefined) {\n    const clean = origin?.trim();\n    this._postMessageOrigin.set(clean || '*');\n  }\n\n  setFromExchange(response: MapaEmbedExchangeResponse) {\n    this._context.set(response.embed);\n    this._config.set(response.embedConfig);\n  }\n\n  patchContext(patch: Partial<MapaEmbedContext>) {\n    const current = this._context();\n    if (!current) return;\n    this._context.set({ ...current, ...patch });\n  }\n\n  setConfig(config: MapaEmbedConfig) {\n    this._config.set(config);\n  }\n\n  hasAction(action: string) {\n    const actions = this._config()?.acciones ?? [];\n    return actions.includes(action);\n  }\n\n  hasPrivilege(key: string) {\n    return !!this._config()?.privilegios?.[key];\n  }\n\n  clear() {\n    this._context.set(null);\n    this._config.set(null);\n    this._postMessageOrigin.set('*');\n  }\n}\n",
    'src/app/features/mapa/embed/services/mapa-embed-auth.service.ts': "import { inject, Injectable } from '@angular/core';\nimport { tap } from 'rxjs';\nimport { SessionStore } from 'src/app/features/seg/store/session.store';\nimport { MapaEmbedApi } from '../data-access/mapa-embed.api';\nimport type { MapaEmbedExchangeResponse, MapaEmbedMode } from '../data-access/mapa-embed.models';\nimport { MapaEmbedContextStore } from '../store/mapa-embed-context.store';\n\n@Injectable({ providedIn: 'root' })\nexport class MapaEmbedAuthService {\n  private readonly api = inject(MapaEmbedApi);\n  private readonly sessionStore = inject(SessionStore);\n  private readonly embedStore = inject(MapaEmbedContextStore);\n\n  exchange(code: string, expectedMode?: MapaEmbedMode) {\n    return this.api.exchange({ code }).pipe(\n      tap((response) => this.applyExchange(response, expectedMode))\n    );\n  }\n\n  applyExchange(response: MapaEmbedExchangeResponse, expectedMode?: MapaEmbedMode) {\n    if (!response?.token) {\n      throw new Error('El backend no devolvió token para el embed.');\n    }\n\n    if (!response.embed) {\n      throw new Error('El backend no devolvió contexto embed.');\n    }\n\n    if (expectedMode && response.embed.mode !== expectedMode) {\n      throw new Error(`El code pertenece a modo ${response.embed.mode}, pero la ruta espera ${expectedMode}.`);\n    }\n\n    const privilegiosEmpresa = response.privilegiosEmpresa ?? [];\n    const menusEmpresa = response.menusEmpresa ?? [];\n\n    this.sessionStore.setSession({\n      token: response.token,\n      user: {\n        id: response.usu,\n        username: response.usuario,\n        catalogo: response.catalogo ?? response.embed.tenant,\n        tipo: response.tipo ?? 0,\n        organizacion: (response.organizacion as any) ?? [],\n      },\n      meta: {\n        environment: response.environment ?? 'embed',\n        contextPath: response.contextPath ?? '/klaxapi',\n        company: response.embed.company,\n        tenant: response.embed.tenant,\n      },\n      privilegiosOrg: [],\n      privilegiosEmpresa,\n      menusEmpresa,\n    });\n\n    this.embedStore.setFromExchange(response);\n  }\n}\n",
    'src/app/features/mapa/embed/services/mapa-embed-messaging.service.ts': "import { Injectable, inject } from '@angular/core';\nimport type { MapaElemento } from '../../data-access/mapa.models';\nimport type { MapaEmbedContext, MapaEmbedMode, MapaElementoCercano } from '../data-access/mapa-embed.models';\nimport { MapaEmbedContextStore } from '../store/mapa-embed-context.store';\n\nexport type KlaxMapMessageType =\n  | 'KLAX_MAP_READY'\n  | 'KLAX_MAP_ERROR'\n  | 'KLAX_MAP_CANCEL'\n  | 'KLAX_MAP_ELEMENT_SELECTED'\n  | 'KLAX_MAP_ELEMENT_VIEWED'\n  | 'KLAX_MAP_BOX_SELECTED'\n  | 'KLAX_MAP_BOX_CREATED'\n  | 'KLAX_MAP_FIBER_CREATED'\n  | 'KLAX_MAP_CREATE_DRAFT_CHANGED';\n\n@Injectable({ providedIn: 'root' })\nexport class MapaEmbedMessagingService {\n  private readonly store = inject(MapaEmbedContextStore);\n\n  post(type: KlaxMapMessageType, payload: unknown = null) {\n    if (typeof window === 'undefined') return;\n    if (!window.parent || window.parent === window) return;\n\n    window.parent.postMessage(\n      {\n        type,\n        payload,\n        timestamp: new Date().toISOString(),\n      },\n      this.store.postMessageOrigin() || '*'\n    );\n  }\n\n  ready(mode: MapaEmbedMode, context: MapaEmbedContext | null) {\n    this.post('KLAX_MAP_READY', { mode, context });\n  }\n\n  error(message: string, detail?: unknown) {\n    this.post('KLAX_MAP_ERROR', { message, detail });\n  }\n\n  cancel() {\n    this.post('KLAX_MAP_CANCEL', {});\n  }\n\n  elementSelected(item: MapaElementoCercano) {\n    this.post('KLAX_MAP_ELEMENT_SELECTED', item);\n  }\n\n  elementViewed(item: MapaElementoCercano) {\n    this.post('KLAX_MAP_ELEMENT_VIEWED', item);\n  }\n\n  boxSelected(item: MapaElementoCercano) {\n    this.post('KLAX_MAP_BOX_SELECTED', item);\n  }\n\n  boxCreated(item: MapaElemento) {\n    this.post('KLAX_MAP_BOX_CREATED', item);\n  }\n\n  fiberCreated(item: MapaElemento) {\n    this.post('KLAX_MAP_FIBER_CREATED', item);\n  }\n}\n",
    'src/app/features/mapa/embed/pages/mapa-embed-admin-shell/mapa-embed-admin-shell.component.ts': "import { CommonModule } from '@angular/common';\nimport { Component, OnInit, inject, signal } from '@angular/core';\nimport { ActivatedRoute } from '@angular/router';\nimport { SessionStore } from 'src/app/features/seg/store/session.store';\nimport { MapaHomeComponent } from '../../../pages/mapa-home/mapa-home.component';\nimport { MapaEmbedAuthService } from '../../services/mapa-embed-auth.service';\nimport { MapaEmbedContextStore } from '../../store/mapa-embed-context.store';\nimport { MapaEmbedMessagingService } from '../../services/mapa-embed-messaging.service';\n\n@Component({\n  selector: 'app-mapa-embed-admin-shell',\n  standalone: true,\n  imports: [CommonModule, MapaHomeComponent],\n  templateUrl: './mapa-embed-admin-shell.component.html',\n  styleUrl: './mapa-embed-admin-shell.component.scss',\n})\nexport class MapaEmbedAdminShellComponent implements OnInit {\n  private readonly route = inject(ActivatedRoute);\n  private readonly auth = inject(MapaEmbedAuthService);\n  private readonly sessionStore = inject(SessionStore);\n  private readonly embedStore = inject(MapaEmbedContextStore);\n  private readonly messaging = inject(MapaEmbedMessagingService);\n\n  readonly loading = signal(true);\n  readonly ready = signal(false);\n  readonly error = signal<string | null>(null);\n\n  ngOnInit() {\n    const origin = this.route.snapshot.queryParamMap.get('origin');\n    this.embedStore.setPostMessageOrigin(origin);\n\n    const code = this.route.snapshot.queryParamMap.get('code');\n\n    if (!code && this.sessionStore.isAuthenticated()) {\n      this.loading.set(false);\n      this.ready.set(true);\n      this.messaging.ready('admin', this.embedStore.context());\n      return;\n    }\n\n    if (!code) {\n      this.fail('Falta el parámetro code para abrir el mapa administrador embebido.');\n      return;\n    }\n\n    this.auth.exchange(code, 'admin').subscribe({\n      next: () => {\n        this.loading.set(false);\n        this.ready.set(true);\n        this.messaging.ready('admin', this.embedStore.context());\n      },\n      error: (err) => {\n        this.fail(err?.error?.mensaje || err?.message || 'No se pudo iniciar el mapa administrador.');\n      },\n    });\n  }\n\n  private fail(message: string) {\n    this.loading.set(false);\n    this.ready.set(false);\n    this.error.set(message);\n    this.messaging.error(message);\n  }\n}\n",
    'src/app/features/mapa/embed/pages/mapa-embed-admin-shell/mapa-embed-admin-shell.component.html': '<div class="embed-admin-state" *ngIf="loading()">\n  <div class="spinner"></div>\n  <p>Iniciando mapa administrador...</p>\n</div>\n\n<div class="embed-admin-state error" *ngIf="!loading() && error()">\n  <h2>No se pudo abrir el mapa</h2>\n  <p>{{ error() }}</p>\n</div>\n\n<app-mapa-home *ngIf="ready()"></app-mapa-home>\n',
    'src/app/features/mapa/embed/pages/mapa-embed-admin-shell/mapa-embed-admin-shell.component.scss': ':host {\n  display: block;\n  width: 100%;\n  height: 100vh;\n  min-height: 520px;\n  background: #0f172a;\n}\n\n.embed-admin-state {\n  width: 100%;\n  height: 100vh;\n  min-height: 520px;\n  display: grid;\n  place-content: center;\n  gap: 1rem;\n  text-align: center;\n  color: #e5e7eb;\n  font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;\n}\n\n.embed-admin-state.error {\n  color: #fecaca;\n}\n\n.spinner {\n  width: 42px;\n  height: 42px;\n  border: 4px solid rgba(255, 255, 255, 0.25);\n  border-top-color: #fff;\n  border-radius: 999px;\n  animation: spin 900ms linear infinite;\n  margin: 0 auto;\n}\n\n@keyframes spin {\n  to {\n    transform: rotate(360deg);\n  }\n}\n',
    'src/app/features/mapa/embed/pages/mapa-embed-viewer/mapa-embed-viewer.component.ts': "import { CommonModule } from '@angular/common';\nimport {\n  AfterViewInit,\n  Component,\n  ElementRef,\n  OnDestroy,\n  OnInit,\n  ViewChild,\n  inject,\n  signal,\n} from '@angular/core';\nimport { FormsModule } from '@angular/forms';\nimport { ActivatedRoute } from '@angular/router';\nimport * as L from 'leaflet';\n\nimport { unwrapOrThrow } from 'src/app/core/api/api-envelope';\nimport { SessionStore } from 'src/app/features/seg/store/session.store';\nimport { MapaElementosApi } from '../../../data-access/elemento/mapa-elementos.api';\nimport type { MapaElemento, MapaElementoSaveRequest } from '../../../data-access/mapa.models';\nimport { MapaEmbedApi } from '../../data-access/mapa-embed.api';\nimport type {\n  MapaEmbedContext,\n  MapaEmbedInitMessage,\n  MapaEmbedMode,\n  MapaElementoCercano,\n} from '../../data-access/mapa-embed.models';\nimport { MapaEmbedAuthService } from '../../services/mapa-embed-auth.service';\nimport { MapaEmbedMessagingService } from '../../services/mapa-embed-messaging.service';\nimport { MapaEmbedContextStore } from '../../store/mapa-embed-context.store';\n\ntype DraftMode = 'none' | 'box' | 'fiber';\n\ninterface LatLngPoint {\n  lat: number;\n  lng: number;\n}\n\n@Component({\n  selector: 'app-mapa-embed-viewer',\n  standalone: true,\n  imports: [CommonModule, FormsModule],\n  templateUrl: './mapa-embed-viewer.component.html',\n  styleUrl: './mapa-embed-viewer.component.scss',\n})\nexport class MapaEmbedViewerComponent implements OnInit, AfterViewInit, OnDestroy {\n  @ViewChild('mapEl') mapEl?: ElementRef<HTMLDivElement>;\n\n  private readonly route = inject(ActivatedRoute);\n  private readonly auth = inject(MapaEmbedAuthService);\n  private readonly sessionStore = inject(SessionStore);\n  private readonly embedStore = inject(MapaEmbedContextStore);\n  private readonly embedApi = inject(MapaEmbedApi);\n  private readonly elementosApi = inject(MapaElementosApi);\n  private readonly messaging = inject(MapaEmbedMessagingService);\n\n  readonly mode = signal<MapaEmbedMode>('vendedor');\n  readonly loading = signal(true);\n  readonly loadingItems = signal(false);\n  readonly saving = signal(false);\n  readonly ready = signal(false);\n  readonly error = signal<string | null>(null);\n\n  readonly context = this.embedStore.context;\n  readonly config = this.embedStore.config;\n\n  readonly items = signal<MapaElementoCercano[]>([]);\n  readonly selected = signal<MapaElementoCercano | null>(null);\n  readonly origin = signal<LatLngPoint | null>(null);\n  readonly radioM = signal<number>(500);\n\n  readonly draftMode = signal<DraftMode>('none');\n  readonly draftPoints = signal<LatLngPoint[]>([]);\n  readonly createError = signal<string | null>(null);\n\n  readonly createForm: {\n    idRedNodoFk: number | null;\n    idGeoTipoElementoFk: number | null;\n    nombre: string;\n    descripcion: string;\n  } = {\n    idRedNodoFk: null,\n    idGeoTipoElementoFk: null,\n    nombre: '',\n    descripcion: '',\n  };\n\n  private map?: L.Map;\n  private originLayer?: L.LayerGroup;\n  private itemsLayer?: L.LayerGroup;\n  private draftLayer?: L.LayerGroup;\n  private layersByElementId = new Map<number, L.Layer>();\n  private readonly messageHandler = (event: MessageEvent) => this.handleParentMessage(event);\n\n  ngOnInit() {\n    const routeMode = (this.route.snapshot.data['mode'] ?? 'vendedor') as MapaEmbedMode;\n    this.mode.set(routeMode);\n\n    const origin = this.route.snapshot.queryParamMap.get('origin');\n    this.embedStore.setPostMessageOrigin(origin);\n\n    if (typeof window !== 'undefined') {\n      window.addEventListener('message', this.messageHandler);\n    }\n\n    this.authenticate(routeMode);\n  }\n\n  ngAfterViewInit() {\n    this.initMap();\n  }\n\n  ngOnDestroy() {\n    if (typeof window !== 'undefined') {\n      window.removeEventListener('message', this.messageHandler);\n    }\n    this.map?.remove();\n  }\n\n  can(key: string) {\n    return !!this.config()?.privilegios?.[key];\n  }\n\n  actionEnabled(action: string) {\n    const actions = this.config()?.acciones ?? [];\n    return actions.length === 0 || actions.includes(action);\n  }\n\n  refreshNearby() {\n    const origin = this.origin();\n    if (!origin) {\n      this.error.set('No hay una ubicación inicial para buscar elementos cercanos.');\n      return;\n    }\n\n    this.loadNearby(origin.lat, origin.lng, this.radioM());\n  }\n\n  centerOrigin() {\n    const origin = this.origin();\n    if (!origin) return;\n    this.map?.setView([origin.lat, origin.lng], Math.max(this.map?.getZoom() ?? 16, 16));\n  }\n\n  focusItem(item: MapaElementoCercano) {\n    this.selected.set(item);\n    this.messaging.elementViewed(item);\n\n    const layer = this.layersByElementId.get(item.idGeoElemento);\n    if (!layer || !this.map) return;\n\n    const anyLayer = layer as any;\n    if (typeof anyLayer.getBounds === 'function') {\n      this.map.fitBounds(anyLayer.getBounds(), { padding: [24, 24], maxZoom: 18 });\n      return;\n    }\n\n    if (typeof anyLayer.getLatLng === 'function') {\n      this.map.setView(anyLayer.getLatLng(), Math.max(this.map.getZoom(), 17));\n    }\n  }\n\n  selectForErp() {\n    const item = this.selected();\n    if (!item) return;\n\n    if (this.mode() === 'tecnico' && this.can('puedeSeleccionarCaja')) {\n      this.messaging.boxSelected(item);\n      return;\n    }\n\n    this.messaging.elementSelected(item);\n  }\n\n  cancel() {\n    this.messaging.cancel();\n  }\n\n  locateBrowser() {\n    if (typeof navigator === 'undefined' || !navigator.geolocation) {\n      this.error.set('Este navegador no permite obtener la ubicación actual.');\n      return;\n    }\n\n    this.loadingItems.set(true);\n\n    navigator.geolocation.getCurrentPosition(\n      (position) => {\n        this.loadingItems.set(false);\n        const lat = position.coords.latitude;\n        const lng = position.coords.longitude;\n        this.setOrigin(lat, lng, this.radioM(), true);\n      },\n      (err) => {\n        this.loadingItems.set(false);\n        this.error.set(err?.message || 'No se pudo obtener la ubicación actual.');\n      },\n      { enableHighAccuracy: true, timeout: 15000, maximumAge: 30000 }\n    );\n  }\n\n  startCreateBox() {\n    if (this.mode() !== 'tecnico') return;\n    if (!this.can('puedeCrearCaja') || !this.actionEnabled('create_box')) {\n      this.createError.set('No tiene permiso para crear caja.');\n      return;\n    }\n\n    this.draftMode.set('box');\n    this.draftPoints.set([]);\n    this.createError.set(null);\n    this.seedCreateForm('Caja nueva');\n  }\n\n  startDrawFiber() {\n    if (this.mode() !== 'tecnico') return;\n    if (!this.can('puedeCrearFibra') || !this.actionEnabled('draw_fiber')) {\n      this.createError.set('No tiene permiso para trazar fibra.');\n      return;\n    }\n\n    this.draftMode.set('fiber');\n    this.draftPoints.set([]);\n    this.createError.set(null);\n    this.seedCreateForm('Tendido de fibra');\n  }\n\n  useOriginAsDraftPoint() {\n    const origin = this.origin();\n    if (!origin) return;\n    this.addDraftPoint(origin);\n  }\n\n  undoDraftPoint() {\n    const points = this.draftPoints();\n    this.draftPoints.set(points.slice(0, Math.max(points.length - 1, 0)));\n    this.redrawDraft();\n  }\n\n  clearDraft() {\n    this.draftMode.set('none');\n    this.draftPoints.set([]);\n    this.createError.set(null);\n    this.createForm.idRedNodoFk = null;\n    this.createForm.idGeoTipoElementoFk = null;\n    this.createForm.nombre = '';\n    this.createForm.descripcion = '';\n    this.redrawDraft();\n  }\n\n  saveDraft() {\n    const draftMode = this.draftMode();\n    const points = this.draftPoints();\n\n    if (draftMode === 'none') return;\n\n    const validation = this.validateCreateForm(draftMode, points);\n    if (validation) {\n      this.createError.set(validation);\n      return;\n    }\n\n    const wkt = draftMode === 'box' ? this.pointWkt(points[0]) : this.lineWkt(points);\n\n    const payload: MapaElementoSaveRequest = {\n      idRedNodoFk: Number(this.createForm.idRedNodoFk),\n      idGeoTipoElementoFk: Number(this.createForm.idGeoTipoElementoFk),\n      nombre: this.createForm.nombre.trim(),\n      descripcion: this.createForm.descripcion?.trim() || null,\n      estado: 'activo',\n      visible: true,\n      origen: 'embed_tecnico',\n      origenRef: this.context()?.trabajoId != null ? String(this.context()?.trabajoId) : null,\n      atributos: this.buildCreateAttributes(draftMode),\n      wkt,\n      latLon: draftMode === 'box' ? `${points[0].lat},${points[0].lng}` : null,\n    };\n\n    this.saving.set(true);\n    this.createError.set(null);\n\n    this.elementosApi.crear(payload).subscribe({\n      next: (resp) => {\n        this.saving.set(false);\n        try {\n          const created = unwrapOrThrow<MapaElemento>(resp);\n          if (draftMode === 'box') this.messaging.boxCreated(created);\n          if (draftMode === 'fiber') this.messaging.fiberCreated(created);\n          this.clearDraft();\n          this.refreshNearby();\n        } catch (err: any) {\n          this.createError.set(err?.message || 'No se pudo crear el elemento.');\n        }\n      },\n      error: (err) => {\n        this.saving.set(false);\n        this.createError.set(err?.error?.mensaje || err?.message || 'No se pudo crear el elemento.');\n      },\n    });\n  }\n\n  private authenticate(expectedMode: MapaEmbedMode) {\n    const code = this.route.snapshot.queryParamMap.get('code');\n\n    if (!code && this.sessionStore.isAuthenticated() && this.embedStore.context()?.mode === expectedMode) {\n      this.afterAuthenticated();\n      return;\n    }\n\n    if (!code) {\n      this.fail('Falta el parámetro code para abrir el mapa embebido.');\n      return;\n    }\n\n    this.auth.exchange(code, expectedMode).subscribe({\n      next: () => this.afterAuthenticated(),\n      error: (err) => this.fail(err?.error?.mensaje || err?.message || 'No se pudo iniciar el mapa embebido.'),\n    });\n  }\n\n  private afterAuthenticated() {\n    this.loading.set(false);\n    this.ready.set(true);\n\n    const ctx = this.context();\n    const config = this.config();\n    this.radioM.set(ctx?.radioM || config?.distanciaM || 500);\n\n    const queryLat = this.numberQueryParam('lat');\n    const queryLng = this.numberQueryParam('lng');\n\n    const lat = queryLat ?? ctx?.lat ?? null;\n    const lng = queryLng ?? ctx?.lng ?? null;\n\n    if (lat != null && lng != null) {\n      this.setOrigin(lat, lng, this.radioM(), true);\n    } else {\n      this.error.set('Mapa iniciado. Esperando ubicación desde el ERP antiguo o navegador.');\n    }\n\n    this.messaging.ready(this.mode(), ctx);\n  }\n\n  private initMap() {\n    if (!this.mapEl?.nativeElement || this.map) return;\n\n    this.map = L.map(this.mapEl.nativeElement, {\n      zoomControl: true,\n      attributionControl: true,\n    }).setView([-2.170998, -79.922359], 14);\n\n    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {\n      maxZoom: 20,\n      attribution: '&copy; OpenStreetMap contributors',\n    }).addTo(this.map);\n\n    this.originLayer = L.layerGroup().addTo(this.map);\n    this.itemsLayer = L.layerGroup().addTo(this.map);\n    this.draftLayer = L.layerGroup().addTo(this.map);\n\n    this.map.on('click', (event: L.LeafletMouseEvent) => {\n      const mode = this.draftMode();\n      if (mode === 'none') return;\n      this.addDraftPoint({ lat: event.latlng.lat, lng: event.latlng.lng });\n    });\n\n    setTimeout(() => this.map?.invalidateSize(), 80);\n  }\n\n  private setOrigin(lat: number, lng: number, radioM: number, load = false) {\n    this.origin.set({ lat, lng });\n    this.radioM.set(radioM);\n\n    this.embedStore.patchContext({ lat, lng, radioM });\n    this.drawOrigin();\n\n    if (this.map) {\n      this.map.setView([lat, lng], Math.max(this.map.getZoom(), 15));\n    }\n\n    if (load) {\n      this.loadNearby(lat, lng, radioM);\n    }\n  }\n\n  private loadNearby(lat: number, lng: number, radioM: number) {\n    this.error.set(null);\n    this.loadingItems.set(true);\n\n    this.embedApi\n      .getElementosCercanos({\n        modo: this.mode(),\n        lat,\n        lng,\n        radioM,\n        limit: this.mode() === 'tecnico' ? 100 : 50,\n        ctx: this.context(),\n      })\n      .subscribe({\n        next: (resp) => {\n          this.loadingItems.set(false);\n          try {\n            const data = unwrapOrThrow(resp);\n            this.items.set(data.items ?? []);\n            this.drawItems();\n          } catch (err: any) {\n            this.error.set(err?.message || 'No se pudo leer elementos cercanos.');\n          }\n        },\n        error: (err) => {\n          this.loadingItems.set(false);\n          this.error.set(err?.error?.mensaje || err?.message || 'No se pudo cargar elementos cercanos.');\n        },\n      });\n  }\n\n  private drawOrigin() {\n    this.originLayer?.clearLayers();\n\n    const origin = this.origin();\n    if (!origin || !this.originLayer) return;\n\n    L.circle([origin.lat, origin.lng], {\n      radius: this.radioM(),\n      weight: 1,\n      fillOpacity: 0.06,\n    }).addTo(this.originLayer);\n\n    L.circleMarker([origin.lat, origin.lng], {\n      radius: 8,\n      weight: 3,\n      fillOpacity: 0.9,\n    })\n      .bindTooltip('Ubicación enviada por ERP', { permanent: false })\n      .addTo(this.originLayer);\n  }\n\n  private drawItems() {\n    this.itemsLayer?.clearLayers();\n    this.layersByElementId.clear();\n\n    if (!this.itemsLayer) return;\n\n    const bounds: L.LatLngExpression[] = [];\n    const origin = this.origin();\n    if (origin) bounds.push([origin.lat, origin.lng]);\n\n    for (const item of this.items()) {\n      const layer = this.layerFromItem(item);\n      if (!layer) continue;\n\n      layer.on('click', () => {\n        this.selected.set(item);\n        this.messaging.elementViewed(item);\n      });\n\n      layer.addTo(this.itemsLayer);\n      this.layersByElementId.set(item.idGeoElemento, layer);\n\n      const center = this.layerCenter(layer);\n      if (center) bounds.push(center);\n    }\n\n    if (this.map && bounds.length > 1) {\n      this.map.fitBounds(L.latLngBounds(bounds), { padding: [32, 32], maxZoom: 17 });\n    }\n  }\n\n  private layerFromItem(item: MapaElementoCercano): L.Layer | null {\n    const parsed = this.parseWkt(item.wkt);\n\n    if (!parsed) {\n      return null;\n    }\n\n    const label = `${item.nombre}${item.distanciaM != null ? ` (${Math.round(item.distanciaM)} m)` : ''}`;\n\n    if (parsed.type === 'point') {\n      return L.circleMarker([parsed.coordinates.lat, parsed.coordinates.lng], {\n        radius: 7,\n        weight: 2,\n        fillOpacity: 0.78,\n      }).bindTooltip(label);\n    }\n\n    if (parsed.type === 'line') {\n      return L.polyline(parsed.coordinates.map((p) => [p.lat, p.lng] as L.LatLngExpression), {\n        weight: 4,\n      }).bindTooltip(label);\n    }\n\n    if (parsed.type === 'polygon') {\n      return L.polygon(parsed.coordinates.map((p) => [p.lat, p.lng] as L.LatLngExpression), {\n        weight: 2,\n        fillOpacity: 0.12,\n      }).bindTooltip(label);\n    }\n\n    return null;\n  }\n\n  private layerCenter(layer: L.Layer): L.LatLngExpression | null {\n    const anyLayer = layer as any;\n\n    if (typeof anyLayer.getLatLng === 'function') {\n      const ll = anyLayer.getLatLng();\n      return [ll.lat, ll.lng];\n    }\n\n    if (typeof anyLayer.getBounds === 'function') {\n      const center = anyLayer.getBounds().getCenter();\n      return [center.lat, center.lng];\n    }\n\n    return null;\n  }\n\n  private addDraftPoint(point: LatLngPoint) {\n    const mode = this.draftMode();\n    if (mode === 'none') return;\n\n    if (mode === 'box') {\n      this.draftPoints.set([point]);\n    } else {\n      this.draftPoints.update((items) => [...items, point]);\n    }\n\n    this.redrawDraft();\n    this.messaging.post('KLAX_MAP_CREATE_DRAFT_CHANGED', {\n      mode,\n      points: this.draftPoints(),\n    });\n  }\n\n  private redrawDraft() {\n    this.draftLayer?.clearLayers();\n\n    if (!this.draftLayer) return;\n\n    const points = this.draftPoints();\n\n    for (const p of points) {\n      L.circleMarker([p.lat, p.lng], {\n        radius: 5,\n        weight: 2,\n        fillOpacity: 0.9,\n      }).addTo(this.draftLayer);\n    }\n\n    if (this.draftMode() === 'fiber' && points.length >= 2) {\n      L.polyline(points.map((p) => [p.lat, p.lng] as L.LatLngExpression), {\n        weight: 4,\n        dashArray: '6 6',\n      }).addTo(this.draftLayer);\n    }\n  }\n\n  private seedCreateForm(defaultName: string) {\n    const firstType = this.config()?.tiposElemento?.[0] ?? null;\n    this.createForm.idGeoTipoElementoFk = firstType;\n    if (!this.createForm.nombre) {\n      this.createForm.nombre = defaultName;\n    }\n  }\n\n  private validateCreateForm(draftMode: DraftMode, points: LatLngPoint[]) {\n    if (!this.createForm.idRedNodoFk || Number(this.createForm.idRedNodoFk) <= 0) {\n      return 'Debe ingresar idRedNodoFk.';\n    }\n\n    if (!this.createForm.idGeoTipoElementoFk || Number(this.createForm.idGeoTipoElementoFk) <= 0) {\n      return 'Debe ingresar idGeoTipoElementoFk.';\n    }\n\n    if (!this.createForm.nombre?.trim()) {\n      return 'Debe ingresar nombre.';\n    }\n\n    if (draftMode === 'box' && points.length !== 1) {\n      return 'Debe marcar un punto para la caja.';\n    }\n\n    if (draftMode === 'fiber' && points.length < 2) {\n      return 'Debe marcar al menos dos puntos para la fibra.';\n    }\n\n    return null;\n  }\n\n  private buildCreateAttributes(draftMode: DraftMode): Record<string, any> {\n    const ctx = this.context();\n    return {\n      embed: true,\n      embedMode: this.mode(),\n      draftMode,\n      trabajoId: ctx?.trabajoId ?? null,\n      clienteId: ctx?.clienteId ?? null,\n      ordenId: ctx?.ordenId ?? null,\n      metadata: ctx?.metadata ?? null,\n    };\n  }\n\n  private pointWkt(point: LatLngPoint) {\n    return `POINT(${point.lng} ${point.lat})`;\n  }\n\n  private lineWkt(points: LatLngPoint[]) {\n    return `LINESTRING(${points.map((p) => `${p.lng} ${p.lat}`).join(',')})`;\n  }\n\n  private handleParentMessage(event: MessageEvent) {\n    const data = event.data as Partial<MapaEmbedInitMessage> | null;\n    if (!data || data.type !== 'KLAX_MAP_INIT') return;\n\n    if (data.mode && data.mode !== this.mode()) {\n      this.error.set(`El ERP envió modo ${data.mode}, pero este visor está en modo ${this.mode()}.`);\n      return;\n    }\n\n    const lat = this.asNumber(data.lat);\n    const lng = this.asNumber(data.lng);\n    const radioM = this.asNumber(data.radioM) ?? this.radioM();\n\n    this.embedStore.patchContext({\n      lat: lat ?? undefined,\n      lng: lng ?? undefined,\n      direccion: data.direccion,\n      radioM,\n      trabajoId: data.trabajoId,\n      clienteId: data.clienteId,\n      ordenId: data.ordenId,\n      metadata: data.metadata,\n    });\n\n    if (lat != null && lng != null) {\n      this.setOrigin(lat, lng, radioM, true);\n    }\n  }\n\n  private parseWkt(wkt?: string | null):\n    | { type: 'point'; coordinates: LatLngPoint }\n    | { type: 'line'; coordinates: LatLngPoint[] }\n    | { type: 'polygon'; coordinates: LatLngPoint[] }\n    | null {\n    if (!wkt) return null;\n\n    const clean = wkt.trim();\n\n    const pointMatch = /^POINT\\s*\\(\\s*([-\\d.]+)\\s+([-\\d.]+)\\s*\\)$/i.exec(clean);\n    if (pointMatch) {\n      return {\n        type: 'point',\n        coordinates: {\n          lng: Number(pointMatch[1]),\n          lat: Number(pointMatch[2]),\n        },\n      };\n    }\n\n    const lineMatch = /^LINESTRING\\s*\\((.+)\\)$/i.exec(clean);\n    if (lineMatch) {\n      const coords = this.parseCoordList(lineMatch[1]);\n      return coords.length ? { type: 'line', coordinates: coords } : null;\n    }\n\n    const polygonMatch = /^POLYGON\\s*\\(\\((.+)\\)\\)$/i.exec(clean);\n    if (polygonMatch) {\n      const coords = this.parseCoordList(polygonMatch[1]);\n      return coords.length ? { type: 'polygon', coordinates: coords } : null;\n    }\n\n    return null;\n  }\n\n  private parseCoordList(raw: string) {\n    return raw\n      .split(',')\n      .map((pair) => {\n        const [lngRaw, latRaw] = pair.trim().split(/\\s+/);\n        return { lng: Number(lngRaw), lat: Number(latRaw) };\n      })\n      .filter((p) => Number.isFinite(p.lat) && Number.isFinite(p.lng));\n  }\n\n  private numberQueryParam(name: string) {\n    return this.asNumber(this.route.snapshot.queryParamMap.get(name));\n  }\n\n  private asNumber(value: unknown): number | null {\n    if (value == null || value === '') return null;\n    const n = Number(value);\n    return Number.isFinite(n) ? n : null;\n  }\n\n  private fail(message: string) {\n    this.loading.set(false);\n    this.ready.set(false);\n    this.error.set(message);\n    this.messaging.error(message);\n  }\n}\n",
    'src/app/features/mapa/embed/pages/mapa-embed-viewer/mapa-embed-viewer.component.html': '<div class="embed-viewer">\n  <aside class="panel">\n    <header>\n      <strong>{{ mode() === \'tecnico\' ? \'Mapa técnico\' : \'Mapa vendedor\' }}</strong>\n      <small *ngIf="context()">Empresa {{ context()?.company }} / {{ context()?.tenant }}</small>\n    </header>\n\n    <section class="state" *ngIf="loading()">\n      Iniciando mapa embebido...\n    </section>\n\n    <section class="state error" *ngIf="!loading() && error()">\n      {{ error() }}\n    </section>\n\n    <section *ngIf="ready()" class="controls">\n      <label>\n        Radio metros\n        <input type="number" min="1" [ngModel]="radioM()" (ngModelChange)="radioM.set(+$event)" />\n      </label>\n\n      <div class="buttons">\n        <button type="button" (click)="refreshNearby()" [disabled]="loadingItems()">Buscar cercanos</button>\n        <button type="button" (click)="centerOrigin()" [disabled]="!origin()">Centrar</button>\n        <button type="button" (click)="locateBrowser()">Mi GPS</button>\n        <button type="button" class="ghost" (click)="cancel()">Cancelar</button>\n      </div>\n\n      <p class="hint" *ngIf="origin()">\n        Origen: {{ origin()?.lat | number:\'1.6-6\' }}, {{ origin()?.lng | number:\'1.6-6\' }}\n      </p>\n\n      <p class="hint" *ngIf="loadingItems()">Cargando elementos cercanos...</p>\n    </section>\n\n    <section *ngIf="ready()" class="items">\n      <h3>Elementos cercanos ({{ items().length }})</h3>\n\n      <button\n        type="button"\n        class="item"\n        *ngFor="let item of items()"\n        [class.selected]="selected()?.idGeoElemento === item.idGeoElemento"\n        (click)="focusItem(item)"\n      >\n        <span>{{ item.nombre }}</span>\n        <small>\n          {{ item.tipoNombre || item.tipoCodigo || \'Elemento\' }}\n          <ng-container *ngIf="item.distanciaM != null">\n            · {{ item.distanciaM | number:\'1.0-0\' }} m\n          </ng-container>\n        </small>\n      </button>\n    </section>\n\n    <section *ngIf="selected()" class="selected-box">\n      <h3>Seleccionado</h3>\n      <p><strong>{{ selected()?.nombre }}</strong></p>\n      <p>{{ selected()?.tipoNombre || selected()?.tipoCodigo }}</p>\n      <p *ngIf="selected()?.distanciaM != null">\n        Distancia: {{ selected()?.distanciaM | number:\'1.0-0\' }} m\n      </p>\n\n      <button type="button" (click)="selectForErp()">\n        {{ mode() === \'tecnico\' ? \'Usar esta caja\' : \'Enviar selección\' }}\n      </button>\n    </section>\n\n    <section *ngIf="mode() === \'tecnico\' && ready()" class="tech-actions">\n      <h3>Trabajo técnico</h3>\n\n      <div class="buttons">\n        <button\n          type="button"\n          (click)="startCreateBox()"\n          [disabled]="!can(\'puedeCrearCaja\') || !actionEnabled(\'create_box\')"\n        >\n          Crear caja\n        </button>\n\n        <button\n          type="button"\n          (click)="startDrawFiber()"\n          [disabled]="!can(\'puedeCrearFibra\') || !actionEnabled(\'draw_fiber\')"\n        >\n          Trazar fibra\n        </button>\n      </div>\n\n      <div class="draft" *ngIf="draftMode() !== \'none\'">\n        <h4>{{ draftMode() === \'box\' ? \'Nueva caja\' : \'Nuevo tendido\' }}</h4>\n        <p class="hint">\n          Haz click en el mapa para marcar puntos.\n          Para caja se usa un punto; para fibra se usan dos o más.\n        </p>\n\n        <label>\n          idRedNodoFk\n          <input type="number" [(ngModel)]="createForm.idRedNodoFk" />\n        </label>\n\n        <label>\n          idGeoTipoElementoFk\n          <input type="number" [(ngModel)]="createForm.idGeoTipoElementoFk" />\n        </label>\n\n        <label>\n          Nombre\n          <input type="text" [(ngModel)]="createForm.nombre" />\n        </label>\n\n        <label>\n          Descripción\n          <textarea rows="2" [(ngModel)]="createForm.descripcion"></textarea>\n        </label>\n\n        <p class="hint">Puntos marcados: {{ draftPoints().length }}</p>\n        <p class="error-text" *ngIf="createError()">{{ createError() }}</p>\n\n        <div class="buttons">\n          <button type="button" (click)="useOriginAsDraftPoint()" [disabled]="!origin()">Usar origen</button>\n          <button type="button" (click)="undoDraftPoint()" [disabled]="!draftPoints().length">Deshacer</button>\n          <button type="button" (click)="saveDraft()" [disabled]="saving()">\n            {{ saving() ? \'Guardando...\' : \'Guardar\' }}\n          </button>\n          <button type="button" class="ghost" (click)="clearDraft()">Cancelar</button>\n        </div>\n      </div>\n    </section>\n  </aside>\n\n  <main class="map-wrap">\n    <div #mapEl class="map"></div>\n  </main>\n</div>\n',
    'src/app/features/mapa/embed/pages/mapa-embed-viewer/mapa-embed-viewer.component.scss': ':host {\n  display: block;\n  width: 100%;\n  height: 100vh;\n  min-height: 520px;\n  overflow: hidden;\n  font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;\n}\n\n.embed-viewer {\n  display: grid;\n  grid-template-columns: minmax(280px, 360px) minmax(0, 1fr);\n  width: 100%;\n  height: 100%;\n  background: #0f172a;\n}\n\n.panel {\n  background: #111827;\n  color: #e5e7eb;\n  border-right: 1px solid rgba(255, 255, 255, 0.12);\n  padding: 14px;\n  overflow: auto;\n}\n\n.panel header {\n  display: grid;\n  gap: 4px;\n  margin-bottom: 14px;\n}\n\n.panel header strong {\n  font-size: 18px;\n}\n\n.panel header small,\n.hint {\n  color: #9ca3af;\n  font-size: 12px;\n}\n\n.state {\n  padding: 10px;\n  border-radius: 10px;\n  background: rgba(59, 130, 246, 0.12);\n  margin-bottom: 12px;\n}\n\n.state.error,\n.error-text {\n  color: #fecaca;\n}\n\n.controls,\n.items,\n.selected-box,\n.tech-actions,\n.draft {\n  display: grid;\n  gap: 10px;\n  margin-bottom: 16px;\n}\n\nh3,\nh4,\np {\n  margin: 0;\n}\n\nlabel {\n  display: grid;\n  gap: 4px;\n  color: #d1d5db;\n  font-size: 12px;\n}\n\ninput,\ntextarea {\n  width: 100%;\n  border: 1px solid #374151;\n  border-radius: 8px;\n  background: #0b1220;\n  color: #e5e7eb;\n  padding: 8px;\n  outline: none;\n}\n\ntextarea {\n  resize: vertical;\n}\n\n.buttons {\n  display: flex;\n  gap: 8px;\n  flex-wrap: wrap;\n}\n\nbutton {\n  border: 0;\n  border-radius: 9px;\n  padding: 8px 10px;\n  background: #2563eb;\n  color: #fff;\n  cursor: pointer;\n}\n\nbutton:hover:not(:disabled) {\n  filter: brightness(1.08);\n}\n\nbutton:disabled {\n  opacity: 0.45;\n  cursor: not-allowed;\n}\n\nbutton.ghost {\n  background: #374151;\n}\n\n.item {\n  width: 100%;\n  display: grid;\n  text-align: left;\n  gap: 2px;\n  background: #1f2937;\n}\n\n.item.selected {\n  outline: 2px solid #60a5fa;\n}\n\n.item small {\n  color: #9ca3af;\n}\n\n.selected-box,\n.draft {\n  border: 1px solid rgba(96, 165, 250, 0.35);\n  border-radius: 12px;\n  padding: 10px;\n  background: rgba(37, 99, 235, 0.1);\n}\n\n.map-wrap {\n  min-width: 0;\n  min-height: 0;\n}\n\n.map {\n  width: 100%;\n  height: 100%;\n}\n\n@media (max-width: 820px) {\n  .embed-viewer {\n    grid-template-columns: 1fr;\n    grid-template-rows: 42vh 58vh;\n  }\n\n  .panel {\n    order: 2;\n    border-right: 0;\n    border-top: 1px solid rgba(255, 255, 255, 0.12);\n  }\n\n  .map-wrap {\n    order: 1;\n  }\n}\n',
    'README_MAPA_EMBED_FRONTEND.md': "# KLAXMAP - Frontend mapa embed\n\nEste paquete agrega rutas y componentes para embeber mapas desde el ERP antiguo.\n\n## Rutas nuevas\n\n```txt\n/embed/mapa/admin?code=...\n/embed/mapa/vendedor?code=...\n/embed/mapa/tecnico?code=...\n```\n\nOpcional:\n\n```txt\n&origin=http://host-del-erp-antiguo\n&lat=-2.170998\n&lng=-79.922359\n```\n\n## Flujo\n\n1. ERP antiguo pide code temporal a `klaxapi`.\n2. ERP antiguo abre iframe apuntando a `/embed/mapa/<modo>?code=...`.\n3. `klaxmap` llama `/api/aut/embed/exchange`.\n4. Se guarda sesión normal en `SessionStore`.\n5. `SessionStore.meta.company` y `SessionStore.meta.tenant` se usan en el interceptor `X-Tenant`.\n6. Vendedor/técnico llaman `/api/erp/mapa/elemento/cercanos`.\n\n## Comunicación con ERP antiguo\n\nEl iframe envía eventos:\n\n```txt\nKLAX_MAP_READY\nKLAX_MAP_ERROR\nKLAX_MAP_CANCEL\nKLAX_MAP_ELEMENT_SELECTED\nKLAX_MAP_ELEMENT_VIEWED\nKLAX_MAP_BOX_SELECTED\nKLAX_MAP_BOX_CREATED\nKLAX_MAP_FIBER_CREATED\n```\n\nEl ERP antiguo puede enviar ubicación nueva al iframe:\n\n```js\niframe.contentWindow.postMessage({\n  type: 'KLAX_MAP_INIT',\n  mode: 'tecnico',\n  lat: -2.170998,\n  lng: -79.922359,\n  radioM: 300,\n  trabajoId: 12345\n}, '*');\n```\n\n## Instalación\n\nDesde la raíz del repo `klaxmap`:\n\n```bash\npython install_mapa_embed_frontend.py --dry-run\npython install_mapa_embed_frontend.py\nnpm run build\n```\n",
}
X_TENANT_CONTENT = "import { HttpInterceptorFn } from '@angular/common/http';\nimport { inject } from '@angular/core';\nimport { SessionStore } from 'src/app/features/seg/store/session.store';\nimport { SKIP_TENANT } from './http-context.tokens';\nimport { ENVIRONMENT, AppEnvironment } from '@core/config/environment.token';\n\nfunction shouldSkipByUrl(url: string) {\n  return url.includes('/api/aut/');\n}\n\nexport const xTenantInterceptor: HttpInterceptorFn = (req, next) => {\n  if (req.context.get(SKIP_TENANT)) return next(req);\n  if (shouldSkipByUrl(req.url)) return next(req);\n\n  const env = inject<AppEnvironment>(ENVIRONMENT);\n  const sessionStore = inject(SessionStore);\n\n  const session = sessionStore.session();\n\n  const companyToSend = session?.meta?.company ?? env.company ?? null;\n  const tenantToSend = session?.meta?.tenant ?? env.tenant ?? null;\n\n  if (req.headers.has('X-Company') && req.headers.has('X-Tenant')) {\n    return next(req);\n  }\n\n  const headers: Record<string, string> = {};\n\n  if (!req.headers.has('X-Company') && companyToSend) {\n    headers['X-Company'] = companyToSend;\n  }\n\n  if (!req.headers.has('X-Tenant') && tenantToSend) {\n    headers['X-Tenant'] = tenantToSend;\n  }\n\n  if (!Object.keys(headers).length) {\n    return next(req);\n  }\n\n  return next(req.clone({ setHeaders: headers }));\n};\n"

def backup(path: Path):
    if not path.exists():
        return
    stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    b = path.with_suffix(path.suffix + f".bak_embed_front_{stamp}")
    shutil.copy2(path, b)
    print(f"backup: {b}")

def write_files(root: Path, dry_run: bool):
    for rel, content in FILES.items():
        target = root / rel
        if dry_run:
            print(f"[dry-run] escribir: {rel}")
            continue
        target.parent.mkdir(parents=True, exist_ok=True)
        if target.exists():
            backup(target)
        target.write_text(content, encoding="utf-8")
        print(f"ok: {rel}")

def patch_app_routes(root: Path, dry_run: bool):
    path = root / "src/app/app.routes.ts"
    text = path.read_text(encoding="utf-8")

    if "path: 'embed/mapa'" in text or 'path: "embed/mapa"' in text:
        print("app.routes.ts ya contiene embed/mapa")
        return

    block = """  {
    path: 'embed/mapa',
    loadChildren: () =>
      import('src/app/features/mapa/embed/mapa-embed.routes').then(
        (m) => m.MAPA_EMBED_ROUTES
      ),
  },

"""

    marker = "  // panel protegido"
    if marker not in text:
        marker = "  {\n    path: 'app'"
        if marker not in text:
            raise RuntimeError("No pude encontrar lugar para insertar ruta embed/mapa en app.routes.ts.")
        new_text = text.replace(marker, block + marker, 1)
    else:
        new_text = text.replace(marker, block + marker, 1)

    if dry_run:
        print("[dry-run] parchear: src/app/app.routes.ts")
        return

    backup(path)
    path.write_text(new_text, encoding="utf-8")
    print("ok: src/app/app.routes.ts")

def patch_session_store(root: Path, dry_run: bool):
    path = root / "src/app/features/seg/store/session.store.ts"
    text = path.read_text(encoding="utf-8")

    if "company?: string;" in text and "tenant?: string;" in text:
        print("SessionStore ya contiene company/tenant en meta")
        return

    old = """export interface SessionMeta {
  environment: string;
  contextPath: string;
}"""

    new = """export interface SessionMeta {
  environment: string;
  contextPath: string;

  /**
   * Contexto opcional para modo embed.
   * Si existe, el interceptor X-Tenant lo usa por encima del environment.
   */
  company?: string;
  tenant?: string;
}"""

    if old not in text:
        raise RuntimeError("No pude encontrar interface SessionMeta para parchear.")

    new_text = text.replace(old, new, 1)

    if dry_run:
        print("[dry-run] parchear: src/app/features/seg/store/session.store.ts")
        return

    backup(path)
    path.write_text(new_text, encoding="utf-8")
    print("ok: src/app/features/seg/store/session.store.ts")

def patch_x_tenant(root: Path, dry_run: bool):
    path = root / "src/app/core/http/x-tenant.interceptor.ts"

    if dry_run:
        print("[dry-run] reemplazar: src/app/core/http/x-tenant.interceptor.ts")
        return

    backup(path)
    path.write_text(X_TENANT_CONTENT, encoding="utf-8")
    print("ok: src/app/core/http/x-tenant.interceptor.ts")

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--dry-run", action="store_true")
    args = parser.parse_args()

    root = Path.cwd()

    if not (root / "package.json").exists():
        raise SystemExit("No encontre package.json. Ejecuta desde la raiz de klaxmap.")

    write_files(root, args.dry_run)
    patch_app_routes(root, args.dry_run)
    patch_session_store(root, args.dry_run)
    patch_x_tenant(root, args.dry_run)

    print("\nListo.")
    print("Siguiente:")
    print("  npm run build")
    print("  git status")
    print("  git add . && git commit -m \"feat: agregar mapas embed\"")

if __name__ == "__main__":
    main()
